var sort = [];
var push = (title, url, type1, type2) => {
    sort.push ({
        title: title,
        url: url,
        style: {
            layout_flexGrow: type1,
            layout_flexBasisPercent: type2
        }
    });
};

var x = [{
        u: "/sort.html",
        ti: "༺ˇ»`类型分类´«ˇ༻",
        se: "ul.sort > li:nth-child(n+3) > a",
        reb: /(.*)\/.*/,
        rea: "$1/{{page}}.html"
    },
    {
        u: "/top/",
        ti: "༺ˇ»`排行分类´«ˇ༻",
        se: "ul.top > li > a",
        reb: /\/$/,
        rea: "/{{page}}.html"
    },
    {
        u: "/qb/",
        ti: "༺ˇ»`完本分类´«ˇ༻",
        se: "ul.sort > li > a",
        reb: /(.*)\/(\d+)\.html/,
        rea: "$1/{{page}}.html"
    }];

x.forEach (i => {
    var o = org.jsoup.Jsoup.parse(java.ajax(i.u));
    var s = o.select(i.se);
    push(i.ti, "", 1, 1);
    s.forEach((j,index) => {
        var url = String (j.attr("href")).replace(i.reb,i.rea);
        if (index + 1 <= s.length - s.length % 3){
        push(j.text(), url, 1, 0.25)
        }else{
        	push(j.text(), url, -1, 0.29)
        	}
    })
});

push("书库",`/sk/0_0_0_{{page}}.html`, 1, 0.62);

